insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('509b1608-a01e-5dc6-8aa9-4e051b7325f6','00000000-0000-0000-0000-00000000b008','sarene','Sarene Residence','project','Căn hộ hạng sang · Lô 6.8 Bắc Sala, Thủ Thiêm','[{"key":"Tên đầy đủ","value":"Sarene Residence & Commercial Complex"},{"key":"Vị trí","value":"Lô 6.8, phân khu Bắc Sala, KĐT Sala, Thủ Thiêm · MT Đại lộ Mai Chí Thọ, P. An Khánh, TP. Thủ Đức"},{"key":"Quy mô đất","value":"~1,63 ha (16.319 m²)"},{"key":"Kết cấu","value":"2 tầng hầm + 3 tầng đế thương mại + tháp căn hộ 21 tầng"},{"key":"Số căn (cần xác minh)","value":"~560 căn hạng sang (có nguồn nêu ~1.200)"},{"key":"Loại căn","value":"1PN–3PN · 50–120 m²"},{"key":"Chủ đầu tư","value":"CTCP Đầu tư Địa ốc Đại Quang Minh (THADICO – THACO)"},{"key":"Phân phối & vận hành","value":"Thiso (thành viên Thaco)"},{"key":"Khởi công","value":"13/01/2026"},{"key":"Mở bán","value":"Dự kiến tháng 6/2026"},{"key":"Bàn giao","value":"Dự kiến tháng 11/2027"}]'::jsonb,null,'Định danh dự án Câu chuyện đầu tư trong 3 dòng: dự án căn hộ đầu tiên ở Sala sau gần 10 năm, do chính chủ đầu tư khu đô thị Sala (THADICO/THACO) phát triển — thừa hưởng ngay hệ sinh thái 105ha hiện hữu tại lõi Thủ Thiêm. Đây là quỹ đất "kim cương" khan hiếm; lợi nhuận chủ yếu đến từ vị thế khan hiếm và tăng giá vốn, không phải dòng tiền thuê.',0),
  ('1452d31b-1030-53b9-b011-c996eaaca5ba','00000000-0000-0000-0000-00000000b008','tq-vitri','Vị trí Lô 6.8 Bắc Sala','project','MT Mai Chí Thọ · 5 phút về Quận 1','[]'::jsonb,null,'Tọa độ "kim cương" Dự án nằm trên Lô 6.8, mặt tiền Đại lộ Mai Chí Thọ — trục xương sống Thủ Thiêm, phân khu phía Bắc của KĐT Sala (P. An Khánh, TP. Thủ Đức). • ~5 phút qua cầu Ba Son hoặc hầm Thủ Thiêm về trung tâm Quận 1 • Gần Metro số 2 và cao tốc Long Thành – Dầu Giây → kết nối sân bay Long Thành & Đông Nam Bộ • Liền kề công viên bờ sông, lâm viên Sala, trung tâm tài chính Thủ Thiêm tương lai',1),
  ('8c3c4b3e-528b-5853-a431-bf9be2a36b8d','00000000-0000-0000-0000-00000000b008','tq-quymo','Quy mô & cấu trúc','project','1,63 ha · tháp 21 tầng · ~560 căn','[{"key":"Diện tích đất","value":"~1,63 ha (16.319 m²)"},{"key":"Kết cấu","value":"2 hầm + 3 tầng đế TM + tháp căn hộ 21 tầng"},{"key":"Số căn","value":"~560 căn (hạng sang, giới hạn)"},{"key":"Loại căn","value":"1PN–3PN · 50–120 m²"}]'::jsonb,null,'Cấu trúc "khối đế thương mại + tháp ở" tạo mô hình phức hợp residence + commercial. Số căn ~560 phù hợp định vị "giới hạn/hạng sang".',2),
  ('1233b141-ac54-5603-9df5-7420582afaf0','00000000-0000-0000-0000-00000000b008','tq-mauthuan','Cảnh báo mâu thuẫn số liệu','project','560 vs 1.200 căn · 1 tháp vs 4 tháp','[]'::jsonb,null,'Nhiều con số quy mô đang lưu hành cho Sarene (dự án mới khởi công 1/2026, chưa có bảng hàng chính thức):',3),
  ('80d99457-7232-54b7-9fba-3f562624cdbc','00000000-0000-0000-0000-00000000b008','tq-thietke','Thiết kế & nhà thầu','project','Ong & Ong · Artelia · Central','[]'::jsonb,null,'Theo nguồn thị trường, đội ngũ phát triển gồm các tên tuổi quốc tế: • Tư vấn thiết kế: Ong & Ong (Singapore) — kiến trúc hiện đại, tối ưu công năng • Quản lý & giám sát: Artelia (Pháp) — tiêu chuẩn an toàn & chất lượng thi công • Tổng thầu: Central Construction Định hướng thiết kế: hạng sang, không gian sống sinh thái, tiện ích nội khu khép kín tiêu chuẩn quốc tế.',4),
  ('be67f19a-3327-5e17-b173-1e573017619a','00000000-0000-0000-0000-00000000b008','tq-sala','Hệ sinh thái Sala 105ha','project','"Mảnh ghép cuối" của Bắc Sala','[]'::jsonb,null,'Điểm bán mạnh nhất của Sarene: sở hữu căn hộ tại đây = thừa hưởng ngay hệ sinh thái 105ha Sala đã hiện hữu — mảng xanh, công viên bờ sông, lâm viên, cộng đồng cư dân tinh hoa sẵn có. Sarene được định vị là "mảnh ghép hoàn hảo" khép kín bức tranh đô thị sinh thái Sala — phân khu Bắc Sala vốn được xem là "lá phổi xanh" của bán đảo Thủ Thiêm.',5),
  ('d60a1fdc-f271-5c44-8448-413a7655fdfd','00000000-0000-0000-0000-00000000b008','tq-dinhvi','Định vị phân khúc','project','Siêu sang lõi Thủ Thiêm · đầu tiên sau ~10 năm','[]'::jsonb,null,'Sarene định vị căn hộ hạng sang/siêu sang tại lõi Thủ Thiêm; là dự án căn hộ đầu tiên tại KĐT Sala sau gần 10 năm — đánh dấu sự "tái khởi động" của Đại Quang Minh sau giai đoạn tập trung hoàn thiện hạ tầng.',6),
  ('cf9c463a-c10a-5ef1-9601-b6990a39252f','00000000-0000-0000-0000-00000000b008','cdt-dqm','Đại Quang Minh (THADICO)','developer','Thành lập 2011 · vốn 14.520 tỷ · Trần Bá Dương','[{"key":"Vốn điều lệ","value":"Tăng từ 10.920 tỷ → 14.520 tỷ đồng (21/01/2025)"},{"key":"Lĩnh vực","value":"BĐS cao cấp + hạ tầng giao thông + khu công nghiệp"},{"key":"Dự án lõi","value":"KĐT Sala (Thủ Thiêm) · tổng vốn ~2,2 tỷ USD"}]'::jsonb,null,'CTCP Đầu tư Địa ốc Đại Quang Minh (THADICO) — thành viên Tập đoàn THACO. Thành lập 22/03/2011, trụ sở số 10 Mai Chí Thọ, An Khánh. Chủ tịch HĐQT ông Trần Bá Dương (Chủ tịch THACO). Là CĐT gắn liền với toàn bộ quá trình hình thành KĐT Sala — năng lực tài chính mạnh, tầm nhìn dài hạn. Sarene là dự án do chính "chủ nhà" của Sala phát triển.',7),
  ('55941aab-5091-5fee-afb3-0f94d8f6f29a','00000000-0000-0000-0000-00000000b008','cdt-thaco','Hệ sinh thái THACO','developer','Tập đoàn đa ngành của Trần Bá Dương','[]'::jsonb,null,'THACO (Trường Hải) là tập đoàn đa ngành (ô tô, nông nghiệp, cơ khí, logistics, BĐS) — hậu thuẫn tài chính cho THADICO. Hệ sinh thái liên quan: Thiso (bán lẻ – Thiso Mall, Emart), KCN Thaco Chu Lai...',8),
  ('9f3da06c-d780-5b81-9917-4c161041e70a','00000000-0000-0000-0000-00000000b008','cdt-track','Track record tại Sala','developer','Sarimi · Sadora · Saroma — tăng giá mạnh','[]'::jsonb,null,'Giai đoạn 2015–2024, doanh thu BĐS của Đại Quang Minh chủ yếu từ các phân khu Sala đã bàn giao: • Căn hộ Sarimi, Sarica, Sarina (Condo C1), Sadora (Lô 6.9) • Biệt thự Saroma, nhà phố Saritown / Nguyễn Cơ Thạch, shophouse khu II Đánh giá thị trường: tiến độ bàn giao đúng hạn/sớm hơn, chất lượng đúng phối cảnh, được ví "Singapore thu nhỏ". Giá thứ cấp các phân khu Sala đã tăng mạnh so mở bán (xem node giá Sarimi/Sarica).',9),
  ('35ed45af-8b7e-52d1-9885-21c6482479b0','00000000-0000-0000-0000-00000000b008','cdt-hatang','Vai trò hạ tầng Thủ Thiêm','developer','4 cầu & đại lộ vòng cung (BT)','[]'::jsonb,null,'THADICO là nhà đầu tư 4 tuyến đường chính + đại lộ vòng cung và cầu Ba Son (Thủ Thiêm 2) trong Thủ Thiêm theo hợp đồng BT (đổi đất lấy hạ tầng) — đây là cách công ty có quỹ đất Sala.',10),
  ('2e219ba1-79d0-5411-9c39-b9f5eda9c15e','00000000-0000-0000-0000-00000000b008','cdt-taichinh','Tài chính & trái phiếu','developer','Lần đầu phát hành 1/2026 · Thaco bảo lãnh','[]'::jsonb,null,'Tháng 1/2026, Đại Quang Minh lần đầu huy động trái phiếu, được Thaco bảo lãnh thanh toán. Giai đoạn 2025–2028, công ty dự kiến ~81% doanh thu đến từ các dự án trong Sala (gồm Sarene).',11),
  ('b15acfec-0550-5c38-8103-cd74dd89b02f','00000000-0000-0000-0000-00000000b008','pl-quyhoach','Quy hoạch & chủ trương','legal','QĐ 3165/2012 · 6 QĐ điều chỉnh 2025','[]'::jsonb,null,'• Lô 6.8 nằm trong đồ án điều chỉnh cục bộ quy hoạch phân khu 1/2.000 theo Quyết định 3165/QĐ-UBND ngày 19/6/2012. • Tháng 7/2025: THADICO nhận 6 quyết định điều chỉnh chủ trương đầu tư tại KĐT Sala (sau khi TP. Thủ Đức công bố 9 đồ án phân khu 1/2.000) — pháp lý quy hoạch Sala được khơi thông.',12),
  ('71b53e95-9202-5319-beca-c1ca96fb88ac','00000000-0000-0000-0000-00000000b008','pl-hientrang','Hiện trạng pháp lý bán hàng','legal','Khởi công 1/2026 · mở bán 6/2026 — xác minh','[]'::jsonb,null,'Dự án khởi công 13/01/2026, dự kiến mở bán tháng 6/2026. Ở thời điểm mở bán sớm, cần xác minh dự án đã có văn bản đủ điều kiện bán nhà ở hình thành trong tương lai của Sở Xây dựng hay chưa.',13),
  ('fa0d770d-cfb0-548c-a380-e65fb665e9f2','00000000-0000-0000-0000-00000000b008','pl-sohuu','Hình thức sở hữu','legal','Căn hộ — lâu dài / 50 năm (xác nhận)','[]'::jsonb,null,'Là căn hộ chung cư hạng sang để ở; thông lệ: sổ hồng lâu dài cho người Việt, 50 năm cho người nước ngoài (room ngoại tối đa 30%/tòa). Phần thương mại khối đế theo thời hạn đất.',14),
  ('7a0fdd06-e3ec-56d1-a72d-28cfb50b98a1','00000000-0000-0000-0000-00000000b008','pl-thiso','Phân phối & vận hành: Thiso','legal','Thành viên Thaco · bảo lãnh NH cần kiểm tra','[]'::jsonb,null,'CTCP Thương mại Dịch vụ Quốc tế Thiso (thành viên Thaco) là đơn vị phân phối & vận hành dự án — đồng thời là đơn vị vận hành bán lẻ Sala (Thiso Mall, Emart). Việc cùng "nhà Thaco" vận hành tạo tính đồng bộ thương mại – cư dân.',15),
  ('77db5220-05b5-59cc-a256-76ddb86551e2','00000000-0000-0000-0000-00000000b008','pl-checklist','Checklist trước cọc','legal','6 bước — chú ý mở bán sớm','[]'::jsonb,null,'• 1. Quyết định chủ trương đầu tư + quy hoạch 1/500/1/2.000 của Lô 6.8. • 2. Giấy phép xây dựng dự án (đã khởi công 1/2026). • 3. Văn bản đủ điều kiện bán nhà ở hình thành trong tương lai — nếu CHƯA có, chỉ "giữ chỗ" hoàn lại. • 4. Bảng giá chính thức từ CĐT/Thiso (không dùng giá rumor để quyết định). • 5. Chứng thư bảo lãnh ngân hàng ghi đúng mã căn + căn đã giải chấp. • 6. Tiến độ thanh toán theo trần luật: ≤70% trước bàn giao (11/2027), ≤95% trước khi cấp sổ.',16),
  ('f64533cb-067f-51e1-9881-c511001261fd','00000000-0000-0000-0000-00000000b008','pk-cancho','Căn hộ & cơ cấu','masterplan','~560 căn · 1–3PN · 50–120 m²','[{"key":"Số căn","value":"~560 căn (hạng sang, giới hạn) — cần xác minh"},{"key":"Loại căn","value":"1PN, 2PN, 3PN"},{"key":"Diện tích","value":"50–120 m²"},{"key":"Tháp","value":"1 tòa 21 tầng (trên 3 tầng đế)"}]'::jsonb,null,'Dải diện tích 50–120 m² phủ từ căn 1PN nhỏ tới 3PN lớn — linh hoạt cho cả người mua ở và tích sản. "Giới hạn ~560 căn" củng cố tính khan hiếm của sản phẩm lõi Sala.',17),
  ('97bab3a5-f16e-5601-9259-6f46d5d04a09','00000000-0000-0000-0000-00000000b008','pk-loaihinh','Phân khúc sản phẩm','masterplan','Hạng sang/siêu sang · giới hạn','[]'::jsonb,null,'Định vị hạng sang đến siêu sang: thiết kế quốc tế, không gian sinh thái, tiện ích nội khu khép kín tiêu chuẩn cao. Sản phẩm "giới hạn" tại lõi Sala — nhắm tệp khách tinh hoa coi trọng địa chỉ & cộng đồng cư dân.',18),
  ('30b9ad5b-9db3-540d-9db4-4a8cc09b0701','00000000-0000-0000-0000-00000000b008','pk-bangiao','Tiêu chuẩn bàn giao','masterplan','Chưa công bố · kỳ vọng hạng sang','[]'::jsonb,null,'CĐT chưa công bố chi tiết tiêu chuẩn bàn giao cho Sarene. Tham chiếu các phân khu Sala trước (Sarimi/Sadora) và phân khúc siêu sang Thủ Thiêm: kỳ vọng bàn giao hoàn thiện cao cấp/nội thất liền tường thương hiệu quốc tế.',19),
  ('6e66fbe5-9046-57e1-8429-0c3df3a96817','00000000-0000-0000-0000-00000000b008','pk-tiendo','Tiến độ & bàn giao','masterplan','Khởi công 1/2026 → bàn giao 11/2027','[]'::jsonb,null,'Chu kỳ xây dựng ~22 tháng từ khởi công đến bàn giao — khá nhanh cho 1 tháp 21 tầng, phù hợp năng lực tổng thầu & cam kết của THADICO.',20),
  ('9f89570c-b834-5fc4-a906-bcc7f5546f98','00000000-0000-0000-0000-00000000b008','pk-thuongmai','Khối đế thương mại','masterplan','3 tầng phố thương mại cao cấp','[]'::jsonb,null,'Dự án là tổ hợp Residence & Commercial: 3 tầng khối đế thương mại tạo phố thương mại cao cấp ngay mặt tiền Mai Chí Thọ, bổ trợ hệ bán lẻ Sala (Thiso Mall/Emart).',21),
  ('9c2502d0-4b86-51e1-9927-e930420b48df','00000000-0000-0000-0000-00000000b008','ti-sala105','Hệ sinh thái Sala 105ha','amenity','Công viên bờ sông · lâm viên · cộng đồng','[]'::jsonb,null,'Cư dân Sarene thừa hưởng ngay 105ha hệ sinh thái Sala hiện hữu: mảng xanh ngút ngàn, công viên bờ sông Sài Gòn, lâm viên, cùng cộng đồng cư dân tinh hoa đã định hình.',22),
  ('9ae31aa0-2170-5fc0-9185-ac0b6285eac1','00000000-0000-0000-0000-00000000b008','ti-noikhu','Tiện ích nội khu','amenity','Khép kín · đang cập nhật','[]'::jsonb,null,'Hệ tiện ích nội khu khép kín tiêu chuẩn hạng sang (hồ bơi, gym, lounge, không gian xanh nội khu…) — CĐT đang cập nhật chi tiết. Mô hình residence khép kín đảm bảo riêng tư & an ninh cho cư dân.',23),
  ('52113695-a703-53d9-a476-37e6ad2eba7a','00000000-0000-0000-0000-00000000b008','ti-thiso','Thiso Mall & bán lẻ','amenity','TTTM Sala · Emart (hệ Thaco)','[]'::jsonb,null,'Khu Sala có hệ bán lẻ do Thiso (hệ Thaco) vận hành — Thiso Mall, đại siêu thị Emart. Sarene nằm trong cùng hệ sinh thái thương mại này, cư dân tiếp cận mua sắm – giải trí hiện hữu.',24),
  ('33f50518-3fef-5ae8-9349-5073adf043d6','00000000-0000-0000-0000-00000000b008','ti-giaoduc-yte','Giáo dục & y tế Sala','amenity','Trường quốc tế · bệnh viện','[]'::jsonb,null,'Hệ tiện ích xã hội Sala (theo quy hoạch/hiện hữu): trường quốc tế (Việt Úc), bệnh viện quốc tế, nhà văn hóa/clubhouse, trung tâm thể thao. Cư dân Sarene tiếp cận các tiện ích này trong cùng khu đô thị.',25),
  ('49921dc4-4e9e-595c-a124-2041b07cb5bd','00000000-0000-0000-0000-00000000b008','ti-caocap','Tiện ích đẳng cấp khu vực','amenity','Bến du thuyền · khách sạn 5 sao','[]'::jsonb,null,'Khu vực Sala/Thủ Thiêm quy hoạch các tiện ích biểu tượng: bến du thuyền, khách sạn 5 sao, khu nghỉ dưỡng sinh thái, công viên cảnh quan ven sông — nâng tầm trải nghiệm sống lõi Thủ Thiêm.',26),
  ('8e4036d7-7615-5e7b-b928-00f6de07c758','00000000-0000-0000-0000-00000000b008','ht-maichitho','Đại lộ Mai Chí Thọ','infra','Trục xương sống Thủ Thiêm','[]'::jsonb,null,'Sarene sở hữu mặt tiền Đại lộ Mai Chí Thọ — trục Đông–Tây xương sống kết nối toàn khu Đông với trung tâm TP.HCM, xuyên qua hầm Thủ Thiêm về Quận 1 và nối cao tốc Long Thành về phía Đông.',27),
  ('892eb570-d42c-51fb-9613-a19f3a7f7427','00000000-0000-0000-0000-00000000b008','ht-cau','Cầu Ba Son & hầm Thủ Thiêm','infra','~5 phút về Quận 1','[]'::jsonb,null,'Kết nối lõi Quận 1 cực nhanh: ~5 phút qua cầu Ba Son (Thủ Thiêm 2) hoặc hầm Thủ Thiêm. Các cầu Thủ Thiêm 1/3/4 và mạng cầu Thủ Thiêm bổ trợ kết nối đa hướng.',28),
  ('3ebefba9-147c-5d79-bd01-6ca2d5fd622c','00000000-0000-0000-0000-00000000b008','ht-cbd','Trung tâm tài chính Thủ Thiêm','infra','CBD mới của TP.HCM','[]'::jsonb,null,'Thủ Thiêm được quy hoạch thành trung tâm tài chính – hành chính – thương mại mới của TP.HCM (CBD mới), với các tháp văn phòng, trung tâm hội nghị, quảng trường trung tâm. Sarene nằm ở lõi khu vực này.',29),
  ('d418bdaa-2360-59e0-a60e-3fa92d5a837f','00000000-0000-0000-0000-00000000b008','ht-metro','Metro 2 · cao tốc · sân bay','infra','Kết nối vùng & Long Thành','[]'::jsonb,null,'Hạ tầng vùng quanh dự án: gần tuyến Metro số 2 (quy hoạch qua Thủ Thiêm) và cao tốc TP.HCM – Long Thành – Dầu Giây → kết nối sân bay Long Thành (vận hành ~cuối 2026) và các tỉnh Đông Nam Bộ.',30),
  ('c54f2845-66ef-50de-a817-f3fed581ad1d','00000000-0000-0000-0000-00000000b008','ht-tod','Mô hình TOD lõi Thủ Thiêm','infra','Đô thị gắn giao thông công cộng','[]'::jsonb,null,'Khu vực hưởng lợi từ mô hình TOD (Transit-Oriented Development) — phát triển đô thị gắn kết giao thông công cộng. Các khu kết nối trực tiếp trục Mai Chí Thọ + lõi Thủ Thiêm nắm lợi thế tuyệt đối về giá trị dài hạn.',31),
  ('3734ab46-e0ef-5de7-85be-dc159e762626','00000000-0000-0000-0000-00000000b008','ht-tacdong','"Điểm rơi": Thủ Thiêm hoàn thiện','infra','Hạ tầng + CBD cộng hưởng giá','[]'::jsonb,null,'Các lớp giá trị cộng hưởng quanh Sarene: • Hệ sinh thái Sala 105ha đã hiện hữu (de-risk) • Cầu Ba Son + hầm Thủ Thiêm + Mai Chí Thọ đã vận hành • CBD tài chính Thủ Thiêm đang hình thành (trung hạn) • Sân bay Long Thành (~cuối 2026), cao tốc mở rộng',32),
  ('50476864-abed-5d3b-bd26-d7bce35b6429','00000000-0000-0000-0000-00000000b008','cs-gia','Giá bán','policy','Rumor 200–250 tr/m² · chưa chính thức','[]'::jsonb,null,'Giá Sarene chưa được CĐT công bố chính thức (mở bán dự kiến 6/2026). Mức rumor 200–250 triệu/m² đang lưu hành — khớp với mặt bằng các phân khu Sala hiện hữu. Với căn 50–120 m², tổng giá ước tính ~10 tỷ tới 30 tỷ+/căn — phân khúc siêu sang, vốn vào rất lớn.',33),
  ('85904e24-ca9c-5dc6-8d42-39da847e0af9','00000000-0000-0000-0000-00000000b008','cs-benchmark','So sánh giá Thủ Thiêm','policy','Empire · Metropole · Lotte · Sala','[]'::jsonb,null,'Sarene (rumor ~200–250) định vị trong nhóm lõi Thủ Thiêm, thấp hơn Empire/Metropole đỉnh nhưng cao hơn hẳn các dự án ngoài lõi (Eaton/TGC). Khoảng cách giá ngoài-lõi (120–210) ↔ lõi (200–500) cho thấy "phần bù vị trí lõi".',34),
  ('d7c1306a-0025-5aa6-b3f7-5635d771d5ce','00000000-0000-0000-0000-00000000b008','cs-thanhtoan','Chính sách thanh toán','policy','Chưa công bố · kỳ vọng giãn tiến độ','[]'::jsonb,null,'Chính sách bán hàng Sarene chưa công bố. Tham chiếu phân khúc cao cấp Thủ Thiêm (vd Empire City): đặt chỗ hoàn lại → ký HĐMB ~10% → đóng giãn mỗi 6 tháng → ~45–50% khi nhận nhà, thường có hỗ trợ vay & ân hạn.',35),
  ('6b97ca97-b6be-5707-aa85-a00bb2079439','00000000-0000-0000-0000-00000000b008','cs-yield','Tỷ suất cho thuê','policy','Siêu sang ~2–3% · lợi nhuận từ tăng giá','[]'::jsonb,null,'Phân khúc siêu sang lõi Thủ Thiêm có tỷ suất cho thuê thấp (~2–3%/năm) do giá vốn rất cao — dù giá thuê tuyệt đối lớn. Lợi nhuận đến chủ yếu từ tăng giá vốn (capital gain), không phải dòng tiền thuê.',36),
  ('228dbfb7-5aff-5c1e-a5f3-472cd4f54e9c','00000000-0000-0000-0000-00000000b008','cs-thitruong','Bối cảnh thị trường Thủ Thiêm','policy','+30%/năm · +84%/2 năm · khan cung','[]'::jsonb,null,'• Mặt bằng giá căn hộ Thủ Thiêm tăng bình quân ~30% trong 1 năm; +84% so 2 năm trước; gấp 3,3 lần so 5 năm trước (Batdongsan, 5/2026). • Sarica/Sarimi Sala tăng 40–80% so 2024–2025. • Động lực: khan hiếm nguồn cung — quỹ đất ven sông & lõi Thủ Thiêm gần như đã phân bổ hết cho các CĐT lớn (Avison Young – ông David Jackson).',37),
  ('20c1fbf6-4253-593f-a977-35e7cfea0b71','00000000-0000-0000-0000-00000000b008','tt-empire','Empire City','comparable','Đại dự án lõi Thủ Thiêm · Keppel & cộng sự','[{"key":"Quy mô","value":"~14,5 ha · 11 phân khu 25–88 tầng · ~3.787 căn"},{"key":"Giá","value":"~210–500 triệu/m² (Cove cao nhất)"},{"key":"Bàn giao toàn KĐT","value":"dự kiến Q1/2028"}]'::jsonb,null,'Đối thủ trực tiếp nặng ký nhất ở lõi Thủ Thiêm. So với Sarene: Empire quy mô lớn hơn nhiều, có tháp biểu tượng 88 tầng & bờ sông; Sarene nhỏ gọn hơn, nằm trong hệ sinh thái Sala đã hoàn thiện và giá vào (rumor 200–250) mềm hơn phân khúc đỉnh Empire.',38),
  ('f76e9750-542b-54a9-9acc-60eac834e468','00000000-0000-0000-0000-00000000b008','tt-metropole','The Metropole Thủ Thiêm','comparable','SonKim Land · siêu sang','[]'::jsonb,null,'The Metropole Thủ Thiêm (SonKim Land) — biểu tượng siêu sang Thủ Thiêm, giá ~170–440 triệu/m², các giai đoạn sau lập đỉnh giá khu vực. Đã bàn giao nhiều giai đoạn, cộng đồng cư dân cao cấp định hình.',39),
  ('bf46450e-fe12-51bd-97d1-414b8e1550a6','00000000-0000-0000-0000-00000000b008','tt-lotte','Lotte Eco Smart City','comparable','Đại dự án · dự đoán ≥300 tr/m²','[]'::jsonb,null,'Lotte Eco Smart City (Lotte) — một trong 4 đại dự án Thủ Thiêm, phức hợp TTTM – văn phòng – căn hộ quy mô lớn. Dù chưa triển khai bán căn hộ rộng rãi, thị trường dự đoán giá không dưới 300 triệu/m².',40),
  ('3f38a03c-1d80-5451-962e-17de827ea26c','00000000-0000-0000-0000-00000000b008','tt-sala-noi','Nội bộ Sala (Sarimi/Sarica)','comparable','Benchmark tăng giá +40–80%','[]'::jsonb,null,'Các phân khu Sala hiện hữu là "đối thủ" thứ cấp đồng thời là benchmark giá & tăng giá cho Sarene: • Sarimi, Sarica, Sadora: thứ cấp 200–260 triệu/m², tăng 40–80% so 2024–2025. • Khách muốn vào Sala có thể chọn căn thứ cấp (vào ở ngay) vs Sarene (mới, chờ bàn giao 11/2027).',41),
  ('7d04ddb7-37aa-565e-b3d5-10122f98ab88','00000000-0000-0000-0000-00000000b008','tt-ngoailoi','Dự án ngoài lõi','comparable','Eaton · TGC · Lumiere: 120–210 tr/m²','[]'::jsonb,null,'Nhóm dự án cao cấp ngoài lõi Thủ Thiêm (cùng khu Đông): Eaton Park, The Global City, Lumiere Riverside, Estella Heights — giá ~120–210 triệu/m², tạo khoảng cách rõ rệt so với lõi Thủ Thiêm.',42),
  ('3845894c-f5f7-58a5-b88a-a207da113a68','00000000-0000-0000-0000-00000000b008','tt-dinhvi','Định vị & SWOT','comparable','Lợi thế / điểm yếu Sarene','[]'::jsonb,null,'Lợi thế (Strengths) • Quỹ đất "kim cương" hiếm tại lõi Sala — dự án căn hộ đầu tiên sau ~10 năm • Chính chủ Sala (THADICO/THACO) phát triển — track record tăng giá + giao đúng hạn • Hệ sinh thái Sala 105ha hiện hữu (de-risk) + kết nối Q1 ~5 phút • Giá vào (rumor ~200–250) mềm hơn Empire/Metropole đỉnh Điểm yếu / Thách thức (Weaknesses) • Giá rumor chưa chính thức; số căn/số tháp mâu thuẫn • Yield thấp (~2–3%), vốn vào rất lớn → kén khách, thanh khoản hẹp • THADICO lịch sử chậm một số hạng mục hạ tầng; vừa lần đầu phát hành trái phiếu • Cạnh tranh đỉnh (Empire/Metropole/Lotte) + hàng thứ cấp Sala',43),
  ('b42987d7-4bf5-5c85-9c26-dbf606dbbe05','00000000-0000-0000-0000-00000000b008','dt-thesis','Luận điểm đầu tư','finance','4 trụ cột — khan hiếm & tích sản lõi','[]'::jsonb,null,'1 · Khan hiếm tuyệt đối lõi Sala Dự án căn hộ đầu tiên ở Sala sau ~10 năm; quỹ đất ven sông/lõi Thủ Thiêm gần như đã hết (Avison Young). 2 · Chính chủ Sala phát triển THADICO/THACO có track record tăng giá (Sarimi/Sarica +40–80%) + giao đúng hạn tại cùng khu. 3 · Hệ sinh thái hiện hữu (de-risk) Thừa hưởng ngay 105ha Sala + kết nối Q1 ~5 phút — không phải "đô thị trên giấy". 4 · Phần bù vị trí lõi Giá vào mềm hơn Empire/Metropole đỉnh, dư địa thu hẹp khoảng cách khi CBD Thủ Thiêm hoàn thiện.',44),
  ('6848f6c1-e052-53bf-ace2-c8a147407e3a','00000000-0000-0000-0000-00000000b008','dt-dongtien','Dòng tiền (mô phỏng)','finance','Vốn lớn · yield thấp → capital gain','[]'::jsonb,null,'Ví dụ căn 2PN ~80 m² × ~220 tr/m² ≈ 17,6 tỷ (ước lượng): Đặc điểm: vốn vào rất lớn; yield ~2–3% không đủ bù lãi vay (~8–10%). Lợi nhuận kỳ vọng đến từ tăng giá vốn theo khan hiếm + CBD hoàn thiện.',45),
  ('d6d872da-777b-51d1-991e-9cd5c744afc3','00000000-0000-0000-0000-00000000b008','dt-ruiro','Bản đồ rủi ro','finance','Giá rumor · số liệu · yield · CĐT','[]'::jsonb,null,null,46),
  ('da646360-6438-5e65-96d2-4aebdaa4d92a','00000000-0000-0000-0000-00000000b008','dt-khuyennghi','Khuyến nghị theo mục tiêu','finance','Ai nên mua — và mua thế nào','[]'::jsonb,null,null,47),
  ('e28ce0df-1116-5c9d-b486-e38a6071adf2','00000000-0000-0000-0000-00000000b008','dt-trigger','Tín hiệu Mua / Thận trọng','finance','Benchmark cập nhật quyết định','[]'::jsonb,null,'Tín hiệu MUA mạnh hơn • CĐT công bố bảng giá chính thức hợp lý (≤ mặt bằng Sala ~200–260) + VB đủ điều kiện bán • Làm rõ số căn/số tháp & tiêu chuẩn bàn giao hạng sang • CBD tài chính Thủ Thiêm & các tiện ích biểu tượng triển khai đúng tiến độ • Thị trường Thủ Thiêm tiếp tục khan cung, thanh khoản tốt Tín hiệu THẬN TRỌNG • Giá mở bán vượt xa mặt bằng Sala mà chưa tương xứng tiện ích • Tiến độ THADICO chậm (lịch sử hạ tầng) hoặc rủi ro tài chính/trái phiếu • Nguồn cung siêu sang Thủ Thiêm bung mạnh (Lotte, Empire mới) làm chững giá • Pháp lý bán hàng/HĐMB chưa rõ ràng tại thời điểm mở bán',48),
  ('76094b90-2e48-5ffa-926c-9ed702f0481b','00000000-0000-0000-0000-00000000b008','dt-kh','Chân dung khách mua','finance','Giới tinh hoa · tích sản · không lướt','[]'::jsonb,null,'Tệp khách Sarene: • Giới tinh hoa / doanh nhân thành đạt coi trọng địa chỉ lõi Thủ Thiêm & cộng đồng cư dân Sala. • Nhà đầu tư tích sản dài hạn — giữ tài sản khan hiếm, kỳ vọng tăng giá vốn (không phụ thuộc dòng thuê). • Khách nước ngoài / Việt kiều (lưu ý room ngoại 30%) ưa "địa chỉ + thương hiệu CĐT".',49);
